function [fitresult, gof] = createFit(x, y)
%CREATEFIT(X,Y)
%  Create a fit.
%
%  Data for 'spline approx' fit:
%      X Input : x
%      Y Output: y
%  Output:
%      fitresult : a fit object representing the fit.
%      gof : structure with goodness-of fit info.
%
%  See also FIT, CFIT, SFIT.

%  Auto-generated by MATLAB on 16-Aug-2021 18:06:29


%% Fit: 'spline approx'.
[xData, yData] = prepareCurveData( x, y );

% Set up fittype and options.
ft = fittype( 'smoothingspline' );

% Fit model to data.
[fitresult, gof] = fit( xData, yData, ft );

% Plot fit with data.
figure( 'Name', 'spline approx' );
h = plot( fitresult, xData, yData );
%legend( h, 'data points', 'spline approx', 'Location', 'NorthEast', 'Interpreter', 'none' );
% Label axes
xlabel( 'FP speed [m/s]', 'Interpreter', 'none','FontSize',11);
ylabel( 'Vibratory answers [%]', 'Interpreter', 'none','FontSize',11);
title('Psychometric function','FontSize',11);
grid on
hold on;
yline(50,'--');
xline(1.17,'--');
legend('off');

ylim([-1 101]);

